begin
  -- Lógica para ENTRADA ou DEVOLUÇÃO (Aumenta o estoque)
  if new.type in ('entry', 'return') then
    update public.unit_stocks
    set quantity = quantity + new.quantity,
        updated_at = now()
    where item_id = new.item_id 
      and unit_id = new.unit_id;
      
  -- Lógica para CONSUMO ou EMPRÉSTIMO (Diminui o estoque)
  elsif new.type in ('consumption', 'loan') then
    -- Opcional: Você pode adicionar uma verificação aqui para impedir estoque negativo
    -- if (select quantity from public.unit_stocks where item_id = new.item_id and unit_id = new.unit_id) < new.quantity then
    --   raise exception 'Estoque insuficiente para esta operação';
    -- end if;

    update public.unit_stocks
    set quantity = quantity - new.quantity,
        updated_at = now()
    where item_id = new.item_id 
      and unit_id = new.unit_id;
  end if;

  return new;
end;

DECLARE
  v_contrato_id UUID;
  v_total NUMERIC(15,2);
BEGIN
  -- Buscar contrato vinculado à solicitação do pedido
  SELECT pr.contrato_id INTO v_contrato_id
  FROM purchase_orders po
  JOIN quotations q ON q.id = po.cotacao_id
  JOIN purchase_requests pr ON pr.id = q.solicitacao_id
  WHERE po.id = NEW.pedido_id
  AND pr.contrato_id IS NOT NULL;

  IF v_contrato_id IS NOT NULL THEN
    -- Somar valores das NFs de todos os pedidos vinculados ao contrato
    SELECT COALESCE(SUM((nf->>'valor')::NUMERIC), 0) INTO v_total
    FROM purchase_orders po
    JOIN quotations q ON q.id = po.cotacao_id
    JOIN purchase_requests pr ON pr.id = q.solicitacao_id,
    LATERAL jsonb_array_elements(po.notas_fiscais) AS nf
    WHERE pr.contrato_id = v_contrato_id;

    UPDATE contracts
    SET valor_consumido = v_total
    WHERE id = v_contrato_id;
  END IF;

  RETURN NEW;
END;

